-- ----------------------------
-- Table structure for student_mastery
-- ----------------------------
DROP TABLE IF EXISTS `student_mastery`;
CREATE TABLE `student_mastery`  (
                                    `id` bigint NOT NULL AUTO_INCREMENT,
                                    `student_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '学生ID',
                                    `knowledge_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '知识点ID',
                                    `course_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '课程ID',
                                    `p_l` double NULL DEFAULT 0.3 COMMENT '当前掌握概率 P(L)',
                                    `p_l0` double NULL DEFAULT 0.3 COMMENT '初始掌握概率 P(L0)',
                                    `p_t` double NULL DEFAULT 0.1 COMMENT '学习转移概率 P(T)',
                                    `p_g` double NULL DEFAULT 0.2 COMMENT '猜测概率 P(G)',
                                    `p_s` double NULL DEFAULT 0.1 COMMENT '失误概率 P(S)',
                                    `total_attempts` int NULL DEFAULT 0 COMMENT '总尝试次数',
                                    `correct_attempts` int NULL DEFAULT 0 COMMENT '正确次数',
                                    `last_attempt_at` datetime NULL DEFAULT NULL COMMENT '最近尝试时间',
                                    `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                    `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                    PRIMARY KEY (`id`) USING BTREE,
                                    UNIQUE INDEX `uk_student_knowledge`(`student_id` ASC, `knowledge_id` ASC) USING BTREE,
                                    INDEX `idx_student_id`(`student_id` ASC) USING BTREE,
                                    INDEX `idx_course_id`(`course_id` ASC) USING BTREE,
                                    INDEX `idx_knowledge_id`(`knowledge_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'BKT学生知识点掌握度' ROW_FORMAT = Dynamic;

