INSERT INTO `submission` VALUES (11, 'SUB1775825880417_204', 'A001', 'S002', NULL, 'submissions/S002_A001_9fd57435.png', 34.00, '📋 **AI智能批改报告**\n\n---\n\n**📷 图片内容识别：**\n图片作业内容（模拟识别）\n\n---\n\n**🎯 答案评估结果：**\n- 内容相似度：0.0%\n- 关键点匹配：0/3\n- 匹配得分：0.0分\n\n---\n\n**✨ 详细反馈：**\n📝 **作业批改报告**\n\n✨ **做得好的地方：**\n1. 字迹工整，书写规范\n2. 解题思路清晰\n3. 大部分题目回答正确\n\n💡 **需要改进的地方：**\n1. 第3题计算有误，建议重新检查\n2. 可以增加一些解题步骤说明\n\n📚 **总体评价：**\n作业完成质量良好！继续保持，相信你会做得更好！加油！💪\n\n\n\n---\n\n**💡 学习建议：**\n需要改进。请重新学习相关知识点，加深理解。\n建议补充以下关键点。\n', 'graded', '2026-04-10 20:58:00', '2026-04-10 21:55:43', NULL, NULL, '图片作业内容（模拟识别）', NULL, NULL);
INSERT INTO `submission` VALUES (12, 'SUB1775827338461_988', 'A002', 'S003', NULL, 'submissions/S003_A002_15b3338f.png', 73.86, '📋 **AI智能批改报告**\n\n---\n\n**⚠️ 提示：当前使用的是本地模拟模式**\n如需更准确的识别效果，请配置智谱AI API Key\n\n---\n\n**📊 详细分析：**\n\n**第1题** ✅ 选择题 - 正确（10/10分）\n**第2题** ✅ 填空题 - 正确（10/10分）\n**第3题** ⚠️ 计算题 - 计算小错（12/15分）\n**第4题** ❌ 应用题 - 方法错误（8/15分）\n**第5题** ⚠️ 证明题 - 不完整（30/40分）\n\n**💡 错误分析与建议：**\n\n• 基本概念理解较好\n• 第3题注意计算准确性\n• 第4题需要重新理解题意和解题方法\n• 建议：多做类似应用题，总结解题规律\n', 'graded', '2026-04-10 21:22:18', '2026-04-10 22:55:20', NULL, NULL, '【图片内容识别】\n\n*作业主题：* 编程作业1\n课程：CS102\n要求：无\n\n*识别到的内容：*\n1. 手写文字内容（模拟）\n2. 数学公式和符号\n3. 解题步骤和答案区域\n\n*注：这是模拟识别结果，实际内容以图片为准*', NULL, NULL);
INSERT INTO `submission` VALUES (13, 'SUB1775835539767_261', 'A1775835317615', 'S001', NULL, 'submissions/S001_A1775835317615_a94c7bcc.png', 75.00, '批改结果\n\n', 'graded', '2026-04-10 23:38:59', '2026-04-11 00:38:47', NULL, NULL, '```json\n{\n    \"score\": \"85\",\n    \"feedback\": {\n        \"content_review\": \"整体上，你的作业表现良好。你对Java的基础概念理解较为清晰，回答问题准确。但在某些细节上仍需注意，如确保答案的完整性、避免拼写错误等。建议你在今后的作业中更加注重细节，不断提高自己的编程能力。\",\n        \"improvement_suggestions\": \"请注意以下几点：\n1. 确保答案的完整性：在回答问题时，请提供完整的代码片段或解释。\n2. 避免拼写错误：在编写代码或回答问题时，请仔细检查并纠正任何拼写错误。\n3. 提高清晰度：为了使你的作业更容易理解，请在书写时保持清晰的字体和结构。\"\n    }\n}\n```', NULL, NULL);
INSERT INTO `submission` VALUES (14, 'SUB1775838083726_235', 'A1775837973873', 'S001', NULL, 'submissions/S001_A1775837973873_9fedc101.jpeg', 75.00, '批改结果\n\n', 'graded', '2026-04-11 00:21:23', '2026-04-18 19:17:16', NULL, NULL, '```json\n{\n    \"score\": \"85\",\n    \"feedback\": \"整体表现良好，但需要注意细节。建议在书写时更加规范，避免出现不必要的错误。\"\n}\n```', NULL, NULL);
INSERT INTO `submission` VALUES (15, 'SUB1775840477174_408', 'A1775835317615', 'S001', NULL, 'submissions/S001_A1775835317615_c988ad93.png', 75.00, '批改结果\n\n', 'graded', '2026-04-11 01:01:17', '2026-04-18 19:17:08', NULL, NULL, '```json\n{\n    \"score\": \"根据您给出的答案，以下是对每个问题的评价和建议：\",\n    \"feedback\": {\n        \"1\": \"正确理解了对象的状态和行为属性，但需要注意类的定义中还包括了变量声明和方法声明。\",\n        \"2\": \"正确指出了Java Applet在HTML文件中运行的特点，但需要明确指出它是一种小程序，而不是完整的应用程序。\",\n        \"3\": \"正确提到了安装JDK后的Java开发工具目录，但建议补充相关的环境配置知识。\",\n        \"4\": \"正确描述了接口的保留字，但可以进一步解释其在编程中的作用。\",\n        \"5\": \"正确说明了类声明的结构，但需要注意实现Runable接口时，类名必须与接口名一致。\",\n        \"6\": \"正确描述了一个完整的Java应用程序的结构，但可以强调主类的重要性以及main方法的签名。\",\n        \"7\": \"正确指出了JDK下解释执行Java程序的命令，但建议补充关于Java虚拟机的知识。\",\n        \"8\": \"正确分析了数组初始化的过程，但可以进一步解释元素赋值的方式。\",\n        \"9\": \"正确完成了程序的编写，但可以优化代码以提高可读性。\"\n    }\n}\n```', NULL, NULL);
INSERT INTO `submission` VALUES (16, 'SUB1775841025480_473', 'A1775835317615', 'S002', NULL, 'submissions/S002_A1775835317615_38da09e6.png', 75.00, '批改结果\n\n', 'graded', '2026-04-11 01:10:25', '2026-04-11 01:11:22', NULL, NULL, '```json\n{\n    \"score\": \"85\",\n    \"feedback\": \"整体表现良好，但需要注意细节。请继续保持。\"\n}\n```', NULL, NULL);
INSERT INTO `submission` VALUES (17, 'SUB1775841062104_663', 'A1775835317615', 'S003', NULL, 'submissions/S003_A1775835317615_d7ac9e85.png', 40.00, '【作业内容】\n\n（1）$-40-28-(-19)+(-24)$\n\n（2）\\left\\frac{1}{3\\frac{1}{4\\frac{1}{6\\right\\times(-24)$\n\n（3）$-1^{4\\frac{1}{6\\times[2-(-3)^{2}]$\n\n（4）$-7^{2}+2\\times(-3)^{2}+(-6)+(-\\frac{1}{3})^{2}$\n\n（5）$3x-2y+5x-4y=3x+5x-2y-4y$\n\n（6）$(a\\frac{1}{2})-(3a\\frac{1}{4})$\n\n（7）$A=2x^{2}-y^{2},B=3y^{2}-2x^{2},求3A-2B的值$\n\n（8）$A=a^{2}+b^{2}+c^{2},B=-4a^{2}+2b^{2}+3c^{2},并且A+B+C=0,求C$\n\n【作业评分】\n根据您给出的评分标准，该学生的作业被评为“优秀”。\n\n【作业反馈】\n\n该学生的作业表现出了出色的数学能力，能够准确地完成各种运算和化简。在解题过程中，他/她展示了清晰的思维和良好的计算习惯。特别是对于第（7）题，能够通过展开并合并同类项来求解，显示出对代数表达式的深刻理解。此外，作业中没有出现抄袭现象，符合您的要求。\n\n然而，在某些地方仍需注意细节，如第（8）题的解答中可能存在一些小错误，建议重新检查。同时，为了进一步提高，可以尝试更简洁的解题方法和更规范的书写。\n\n总体来说，这是一个非常棒的开始，希望继续保持这种优秀的表现！', 'graded', '2026-04-11 01:11:02', '2026-04-11 01:23:55', NULL, NULL, '【作业内容】\n\n（1）$-40-28-(-19)+(-24)$\n\n（2）\\left\\frac{1}{3\\frac{1}{4\\frac{1}{6\\right\\times(-24)$\n\n（3）$-1^{4\\frac{1}{6\\times[2-(-3)^{2}]$\n\n（4）$-7^{2}+2\\times(-3)^{2}+(-6)+(-\\frac{1}{3})^{2}$\n\n（5）$3x-2y+5x-4y=3x+5x-2y-4y$\n\n（6）$(a\\frac{1}{2})-(3a\\frac{1}{4})$\n\n（7）$A=2x^{2}-y^{2},B=3y^{2}-2x^{2},求3A-2B的值$\n\n（8）$A=a^{2}+b^{2}+c^{2},B=-4a^{2}+2b^{2}+3c^{2},并且A+B+C=0,求C$\n\n【作业评分】\n根据您给出的评分标准，该学生的作业被评为“优秀”。\n\n【作业反馈】\n\n该学生的作业表现出了出色的数学能力，能够准确地完成各种运算和化简。在解题过程中，他/她展示了清晰的思维和良好的计算习惯。特别是对于第（7）题，能够通过展开并合并同类项来求解，显示出对代数表达式的深刻理解。此外，作业中没有出现抄袭现象，符合您的要求。\n\n然而，在某些地方仍需注意细节，如第（8）题的解答中可能存在一些小错误，建议重新检查。同时，为了进一步提高，可以尝试更简洁的解题方法和更规范的书写。\n\n总体来说，这是一个非常棒的开始，希望继续保持这种优秀的表现！', NULL, NULL);
