-- ----------------------------
-- Table structure for workflow_execution
-- ----------------------------
DROP TABLE IF EXISTS `workflow_execution`;
CREATE TABLE `workflow_execution`  (
                                       `id` bigint NOT NULL AUTO_INCREMENT,
                                       `execution_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '执行ID',
                                       `workflow_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '工作流ID',
                                       `workflow_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '工作流名称',
                                       `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'PENDING' COMMENT '状态',
                                       `context` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '执行上下文(JSON)',
                                       `result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '执行结果(JSON)',
                                       `step_count` int NULL DEFAULT 0 COMMENT '步骤数',
                                       `error` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '错误信息',
                                       `started_at` datetime NULL DEFAULT NULL COMMENT '开始时间',
                                       `completed_at` datetime NULL DEFAULT NULL COMMENT '完成时间',
                                       `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                       PRIMARY KEY (`id`) USING BTREE,
                                       UNIQUE INDEX `uk_execution_id`(`execution_id` ASC) USING BTREE,
                                       INDEX `idx_workflow_id`(`workflow_id` ASC) USING BTREE,
                                       INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '工作流执行记录' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of workflow_execution
-- ----------------------------

